                    const cellContent = escapeHTML(data[i][j]);  // Escape for safety
                    if (i === 0) {
                        // First row as headers
                        tableHTML += `<th>${cellContent}</th>`;
                    } else {
                        tableHTML += `<td>${cellContent}</td>`;
